PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:12', 73, 12, 29, 574, 5487, 'اِنَّ لَدَيْنَآ اَنْكَالًا وَّجَحِيْمًاۙ', 'Sesungguhnya di sisi Kami ada belenggu-belenggu (yang berat), (neraka) Jahim,', '', 'https://everyayah.com/data/Alafasy_128kbps/073012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:13', 73, 13, 29, 574, 5488, 'وَّطَعَامًا ذَا غُصَّةٍ وَّعَذَابًا اَلِيْمًا ', 'makanan yang menyumbat kerongkongan, dan azab yang pedih.', '', 'https://everyayah.com/data/Alafasy_128kbps/073013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:14', 73, 14, 29, 574, 5489, 'يَوْمَ تَرْجُفُ الْاَرْضُ وَالْجِبَالُ وَكَانَتِ الْجِبَالُ كَثِيْبًا مَّهِيْلًا ', '(Ingatlah) pada hari (ketika) bumi dan gunung-gunung berguncang keras dan gunung-gunung itu menjadi seperti onggokan pasir yang tercurah.', '', 'https://everyayah.com/data/Alafasy_128kbps/073014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:15', 73, 15, 29, 574, 5490, 'اِنَّآ اَرْسَلْنَآ اِلَيْكُمْ رَسُوْلًا ەۙ شَاهِدًا عَلَيْكُمْ كَمَآ اَرْسَلْنَآ اِلٰى فِرْعَوْنَ رَسُوْلًا ۗ', 'Sesungguhnya Kami telah mengutus seorang rasul (Nabi Muhammad) kepadamu sebagai saksi atasmu, sebagaimana Kami telah mengutus seorang rasul kepada Fir‘aun.', '', 'https://everyayah.com/data/Alafasy_128kbps/073015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:16', 73, 16, 29, 574, 5491, 'فَعَصٰى فِرْعَوْنُ الرَّسُوْلَ فَاَخَذْنٰهُ اَخْذًا وَّبِيْلًاۚ', 'Namun, Fir‘aun mendurhakai rasul itu sehingga Kami siksa dia dengan siksaan yang berat. ', '', 'https://everyayah.com/data/Alafasy_128kbps/073016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:17', 73, 17, 29, 574, 5492, 'فَكَيْفَ تَتَّقُوْنَ اِنْ كَفَرْتُمْ يَوْمًا يَّجْعَلُ الْوِلْدَانَ شِيْبًاۖ', 'Lalu, bagaimanakah kamu akan dapat menjaga dirimu (dari azab) hari yang menjadikan anak-anak beruban jika kamu tetap kufur?', '', 'https://everyayah.com/data/Alafasy_128kbps/073017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:18', 73, 18, 29, 574, 5493, ' ۨالسَّمَاۤءُ مُنْفَطِرٌۢ بِهٖۗ كَانَ وَعْدُهٗ مَفْعُوْلًا', 'Langit terbelah padanya (hari itu). Janji-Nya pasti terlaksana.', '', 'https://everyayah.com/data/Alafasy_128kbps/073018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:19', 73, 19, 29, 574, 5494, 'اِنَّ هٰذِهٖ تَذْكِرَةٌ ۚ فَمَنْ شَاۤءَ اتَّخَذَ اِلٰى رَبِّهٖ سَبِيْلًا ࣖ ', 'Sesungguhnya ini adalah peringatan. Siapa yang berkehendak niscaya mengambil jalan (yang lurus) kepada Tuhannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/073019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:20', 73, 20, 29, 575, 5495, '۞ اِنَّ رَبَّكَ يَعْلَمُ اَنَّكَ تَقُوْمُ اَدْنٰى مِنْ ثُلُثَيِ الَّيْلِ وَنِصْفَهٗ وَثُلُثَهٗ وَطَاۤىِٕفَةٌ مِّنَ الَّذِيْنَ مَعَكَۗ وَاللّٰهُ يُقَدِّرُ الَّيْلَ وَالنَّهَارَۗ عَلِمَ اَنْ لَّنْ تُحْصُوْهُ فَتَابَ عَلَيْكُمْ فَاقْرَءُوْا مَا تَيَسَّرَ مِنَ الْقُرْاٰنِۗ عَلِمَ اَنْ سَيَكُوْنُ مِنْكُمْ مَّرْضٰىۙ وَاٰخَرُوْنَ يَضْرِبُوْنَ فِى الْاَرْضِ يَبْتَغُوْنَ مِنْ فَضْلِ اللّٰهِ ۙوَاٰخَرُوْنَ يُقَاتِلُوْنَ فِيْ سَبِيْلِ اللّٰهِ ۖفَاقْرَءُوْا مَا تَيَسَّرَ مِنْهُۙ وَاَقِيْمُوا الصَّلٰوةَ وَاٰتُوا الزَّكٰوةَ وَاَقْرِضُوا اللّٰهَ قَرْضًا حَسَنًاۗ وَمَا تُقَدِّمُوْا لِاَنْفُسِكُمْ مِّنْ خَيْرٍ تَجِدُوْهُ عِنْدَ اللّٰهِ ۙهُوَ خَيْرًا وَّاَعْظَمَ اَجْرًاۗ وَاسْتَغْفِرُوا اللّٰهَ ۗاِنَّ اللّٰهَ غَفُوْرٌ رَّحِيْمٌ ࣖ ', 'Sesungguhnya Tuhanmu mengetahui bahwa engkau (Nabi Muhammad) berdiri (salat) kurang dari dua pertiga malam, atau seperdua malam atau sepertiganya dan (demikian pula) segolongan dari orang-orang yang bersamamu. Allah menetapkan ukuran malam dan siang. Allah mengetahui bahwa kamu tidak dapat menghitungnya (secara terperinci waktu-waktu tersebut sehingga menyulitkanmu dalam melaksanakan salat malam). Maka, Dia kembali (memberi keringanan) kepadamu. Oleh karena itu, bacalah (ayat) Al-Qur’an yang mudah (bagimu). Dia mengetahui bahwa akan ada di antara kamu orang-orang yang sakit, dan yang lain berjalan di bumi mencari sebagian karunia Allah serta yang lain berperang di jalan Allah, maka bacalah apa yang mudah (bagimu) darinya (Al-Qur’an). Tegakkanlah salat, tunaikanlah zakat, dan berikanlah pinjaman kepada Allah pinjaman yang baik. Kebaikan apa saja yang kamu perbuat untuk dirimu niscaya kamu memperoleh (balasan)-nya di sisi Allah sebagai balasan yang paling baik dan yang paling besar pahalanya. Mohonlah ampunan kepada Allah. Sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/073020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:1', 74, 1, 29, 575, 5496, 'يٰٓاَيُّهَا الْمُدَّثِّرُۙ', 'Wahai orang yang berselimut (Nabi Muhammad),', '', 'https://everyayah.com/data/Alafasy_128kbps/074001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:2', 74, 2, 29, 575, 5497, 'قُمْ فَاَنْذِرْۖ', 'bangunlah, lalu berilah peringatan!', '', 'https://everyayah.com/data/Alafasy_128kbps/074002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:3', 74, 3, 29, 575, 5498, 'وَرَبَّكَ فَكَبِّرْۖ', 'Tuhanmu, agungkanlah!', '', 'https://everyayah.com/data/Alafasy_128kbps/074003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:4', 74, 4, 29, 575, 5499, 'وَثِيَابَكَ فَطَهِّرْۖ', 'Pakaianmu, bersihkanlah!', '', 'https://everyayah.com/data/Alafasy_128kbps/074004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:5', 74, 5, 29, 575, 5500, 'وَالرُّجْزَ فَاهْجُرْۖ ', 'Segala (perbuatan) yang keji, tinggalkanlah!', '', 'https://everyayah.com/data/Alafasy_128kbps/074005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:6', 74, 6, 29, 575, 5501, 'وَلَا تَمْنُنْ تَسْتَكْثِرُۖ ', 'Janganlah memberi (dengan maksud) memperoleh (balasan) yang lebih banyak!', '', 'https://everyayah.com/data/Alafasy_128kbps/074006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:7', 74, 7, 29, 575, 5502, 'وَلِرَبِّكَ فَاصْبِرْۗ ', 'Karena Tuhanmu, bersabarlah!', '', 'https://everyayah.com/data/Alafasy_128kbps/074007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:8', 74, 8, 29, 575, 5503, 'فَاِذَا نُقِرَ فِى النَّاقُوْرِۙ ', 'Apabila sangkakala ditiup,', '', 'https://everyayah.com/data/Alafasy_128kbps/074008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:9', 74, 9, 29, 575, 5504, 'فَذٰلِكَ يَوْمَىِٕذٍ يَّوْمٌ عَسِيْرٌۙ ', 'hari itulah hari yang sulit,', '', 'https://everyayah.com/data/Alafasy_128kbps/074009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:10', 74, 10, 29, 575, 5505, 'عَلَى الْكٰفِرِيْنَ غَيْرُ يَسِيْرٍ ', '(yang) tidak mudah bagi orang-orang kafir. ', '', 'https://everyayah.com/data/Alafasy_128kbps/074010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:11', 74, 11, 29, 575, 5506, 'ذَرْنِيْ وَمَنْ خَلَقْتُ وَحِيْدًاۙ ', 'Biarkanlah Aku (yang bertindak) terhadap orang yang Aku ciptakan dia dalam kesendirian.733)', '733) Ayat ini dan beberapa ayat berikutnya diturunkan mengenai al-Walid bin al-Mugirah, pemimpin kafir Quraisy, yang sebelumnya tidak memiliki apa-apa.', 'https://everyayah.com/data/Alafasy_128kbps/074011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:12', 74, 12, 29, 575, 5507, 'وَّجَعَلْتُ لَهٗ مَالًا مَّمْدُوْدًاۙ ', 'Aku beri dia kekayaan yang berlimpah,', '', 'https://everyayah.com/data/Alafasy_128kbps/074012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:13', 74, 13, 29, 575, 5508, 'وَّبَنِيْنَ شُهُوْدًاۙ ', 'anak-anak yang selalu bersamanya,', '', 'https://everyayah.com/data/Alafasy_128kbps/074013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:14', 74, 14, 29, 575, 5509, 'وَّمَهَّدْتُّ لَهٗ تَمْهِيْدًاۙ ', 'dan Aku beri dia kelapangan (hidup) seluas-luasnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/074014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:15', 74, 15, 29, 575, 5510, 'ثُمَّ يَطْمَعُ اَنْ اَزِيْدَۙ    ', 'Kemudian, dia ingin sekali agar Aku menambahnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/074015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:16', 74, 16, 29, 575, 5511, 'كَلَّاۗ اِنَّهٗ كَانَ لِاٰيٰتِنَا عَنِيْدًاۗ ', 'Sekali-kali tidak! Sesungguhnya dia telah menentang ayat-ayat Kami (Al-Qur’an).', '', 'https://everyayah.com/data/Alafasy_128kbps/074016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:17', 74, 17, 29, 575, 5512, 'سَاُرْهِقُهٗ صَعُوْدًاۗ ', 'Aku akan membebaninya dengan pendakian yang memayahkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/074017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:18', 74, 18, 29, 576, 5513, 'اِنَّهٗ فَكَّرَ وَقَدَّرَۙ ', 'Sesungguhnya dia telah memikirkan dan menetapkan (apa yang ditetapkannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/074018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:19', 74, 19, 29, 576, 5514, 'فَقُتِلَ كَيْفَ قَدَّرَۙ ', 'Maka, binasalah dia. Bagaimanakah dia menetapkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/074019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:20', 74, 20, 29, 576, 5515, 'ثُمَّ قُتِلَ كَيْفَ قَدَّرَۙ ', 'Kemudian, binasalah dia. Bagaimanakah dia menetapkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/074020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:21', 74, 21, 29, 576, 5516, 'ثُمَّ نَظَرَۙ ', 'Kemudian dia memikirkan (untuk melecehkan Al-Qur’an).', '', 'https://everyayah.com/data/Alafasy_128kbps/074021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:22', 74, 22, 29, 576, 5517, 'ثُمَّ عَبَسَ وَبَسَرَۙ ', 'Kemudian, dia berwajah masam dan cemberut (karena tidak menemukan kelemahan Al-Qur’an).', '', 'https://everyayah.com/data/Alafasy_128kbps/074022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:23', 74, 23, 29, 576, 5518, 'ثُمَّ اَدْبَرَ وَاسْتَكْبَرَۙ ', 'Kemudian, dia berpaling (dari kebenaran) dan menyombongkan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/074023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:24', 74, 24, 29, 576, 5519, 'فَقَالَ اِنْ هٰذَآ اِلَّا سِحْرٌ يُّؤْثَرُۙ ', 'Lalu, dia berkata, “(Al-Qur’an) ini tidak lain, kecuali sihir yang dipelajari (dari orang-orang terdahulu).', '', 'https://everyayah.com/data/Alafasy_128kbps/074024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:25', 74, 25, 29, 576, 5520, 'اِنْ هٰذَآ اِلَّا قَوْلُ الْبَشَرِۗ ', 'Ini tidak lain kecuali perkataan manusia.”', '', 'https://everyayah.com/data/Alafasy_128kbps/074025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:26', 74, 26, 29, 576, 5521, 'سَاُصْلِيْهِ سَقَرَ', 'Aku akan memasukkannya ke dalam (neraka) Saqar.', '', 'https://everyayah.com/data/Alafasy_128kbps/074026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:27', 74, 27, 29, 576, 5522, 'وَمَآ اَدْرٰىكَ مَا سَقَرُۗ ', 'Tahukah kamu apa (neraka) Saqar itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/074027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:28', 74, 28, 29, 576, 5523, 'لَا تُبْقِيْ وَلَا تَذَرُۚ ', '(Neraka Saqar itu) tidak meninggalkan (sedikit pun bagian jasmani) dan tidak membiarkan(-nya luput dari siksaan).', '', 'https://everyayah.com/data/Alafasy_128kbps/074028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:29', 74, 29, 29, 576, 5524, 'لَوَّاحَةٌ لِّلْبَشَرِۚ ', '(Neraka Saqar itu) menghanguskan kulit manusia.', '', 'https://everyayah.com/data/Alafasy_128kbps/074029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:30', 74, 30, 29, 576, 5525, 'عَلَيْهَا تِسْعَةَ عَشَرَۗ ', 'Di atasnya ada sembilan belas (malaikat penjaga).', '', 'https://everyayah.com/data/Alafasy_128kbps/074030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:31', 74, 31, 29, 576, 5526, 'وَمَا جَعَلْنَآ اَصْحٰبَ النَّارِ اِلَّا مَلٰۤىِٕكَةً ۖوَّمَا جَعَلْنَا عِدَّتَهُمْ اِلَّا فِتْنَةً لِّلَّذِيْنَ كَفَرُوْاۙ لِيَسْتَيْقِنَ الَّذِيْنَ اُوْتُوا الْكِتٰبَ وَيَزْدَادَ الَّذِيْنَ اٰمَنُوْٓا اِيْمَانًا وَّلَا يَرْتَابَ الَّذِيْنَ اُوْتُوا الْكِتٰبَ وَالْمُؤْمِنُوْنَۙ وَلِيَقُوْلَ الَّذِيْنَ فِيْ قُلُوْبِهِمْ مَّرَضٌ وَّالْكٰفِرُوْنَ مَاذَآ اَرَادَ اللّٰهُ بِهٰذَا مَثَلًاۗ  كَذٰلِكَ يُضِلُّ اللّٰهُ مَنْ يَّشَاۤءُ وَيَهْدِيْ مَنْ يَّشَاۤءُۗ وَمَا يَعْلَمُ جُنُوْدَ رَبِّكَ اِلَّا هُوَۗ وَمَا هِيَ اِلَّا ذِكْرٰى لِلْبَشَرِ ࣖ', 'Kami tidak menjadikan para penjaga neraka, kecuali para malaikat dan Kami tidak menentukan bilangan mereka itu, kecuali sebagai cobaan bagi orang-orang kafir. (Yang demikian itu) agar orang-orang yang diberi kitab menjadi yakin, orang yang beriman bertambah imannya, orang-orang yang diberi kitab dan orang-orang mukmin itu tidak ragu-ragu, serta orang-orang yang di dalam hatinya ada penyakit dan orang-orang kafir (berkata,) “Apakah yang dikehendaki Allah dengan (bilangan) ini sebagai suatu perumpamaan?” Demikianlah Allah membiarkan sesat orang-orang yang Dia kehendaki (berdasarkan kecenderungan dan pilihan mereka sendiri) dan memberi petunjuk kepada orang-orang yang Dia kehendaki (berdasarkan kesiapan mereka untuk menerima petunjuk). Tidak ada yang mengetahui bala tentara Tuhanmu kecuali Dia sendiri. Ia (neraka Saqar itu) tidak lain hanyalah peringatan bagi manusia.', '', 'https://everyayah.com/data/Alafasy_128kbps/074031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:32', 74, 32, 29, 576, 5527, 'كَلَّا وَالْقَمَرِۙ', 'Sekali-kali tidak!734) Demi bulan,', '734) Kalimat ini merupakan bantahan terhadap ucapan orang-orang musyrik yang mengingkari hal-hal tersebut di atas.', 'https://everyayah.com/data/Alafasy_128kbps/074032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:33', 74, 33, 29, 576, 5528, 'وَالَّيْلِ اِذْ اَدْبَرَۙ', 'demi malam ketika telah berlalu,', '', 'https://everyayah.com/data/Alafasy_128kbps/074033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:34', 74, 34, 29, 576, 5529, 'وَالصُّبْحِ اِذَآ اَسْفَرَۙ', 'dan demi subuh apabila mulai terang,', '', 'https://everyayah.com/data/Alafasy_128kbps/074034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:35', 74, 35, 29, 576, 5530, 'اِنَّهَا لَاِحْدَى الْكُبَرِۙ', 'sesungguhnya ia (neraka Saqar itu) benar-benar salah satu (bencana) yang sangat besar,', '', 'https://everyayah.com/data/Alafasy_128kbps/074035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:36', 74, 36, 29, 576, 5531, 'نَذِيْرًا لِّلْبَشَرِۙ', 'sebagai peringatan bagi manusia,', '', 'https://everyayah.com/data/Alafasy_128kbps/074036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:37', 74, 37, 29, 576, 5532, 'لِمَنْ شَاۤءَ مِنْكُمْ اَنْ يَّتَقَدَّمَ اَوْ يَتَاَخَّرَۗ', '(yaitu) bagi siapa di antara kamu yang ingin maju (meraih kebajikan) atau mundur (dengan berbuat maksiat).', '', 'https://everyayah.com/data/Alafasy_128kbps/074037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:38', 74, 38, 29, 576, 5533, 'كُلُّ نَفْسٍۢ بِمَا كَسَبَتْ رَهِيْنَةٌۙ', 'Setiap orang bertanggung jawab atas apa yang telah ia lakukan,', '', 'https://everyayah.com/data/Alafasy_128kbps/074038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:39', 74, 39, 29, 576, 5534, 'اِلَّآ اَصْحٰبَ الْيَمِيْنِ ۛ ', 'kecuali golongan kanan,', '', 'https://everyayah.com/data/Alafasy_128kbps/074039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:40', 74, 40, 29, 576, 5535, 'فِيْ جَنّٰتٍ ۛ يَتَسَاۤءَلُوْنَۙ', 'berada di dalam surga yang mereka saling bertanya', '', 'https://everyayah.com/data/Alafasy_128kbps/074040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:41', 74, 41, 29, 576, 5536, 'عَنِ الْمُجْرِمِيْنَۙ', 'tentang (keadaan) para pendurhaka,', '', 'https://everyayah.com/data/Alafasy_128kbps/074041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:42', 74, 42, 29, 576, 5537, 'مَا سَلَكَكُمْ فِيْ سَقَرَ ', '“Apa yang menyebabkan kamu masuk ke dalam (neraka) Saqar?”', '', 'https://everyayah.com/data/Alafasy_128kbps/074042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:43', 74, 43, 29, 576, 5538, 'قَالُوْا لَمْ نَكُ مِنَ الْمُصَلِّيْنَۙ', 'Mereka menjawab, “Dahulu kami tidak termasuk orang-orang yang melaksanakan salat', '', 'https://everyayah.com/data/Alafasy_128kbps/074043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:44', 74, 44, 29, 576, 5539, 'وَلَمْ نَكُ نُطْعِمُ الْمِسْكِيْنَۙ', 'dan kami (juga) tidak memberi makan orang miskin.', '', 'https://everyayah.com/data/Alafasy_128kbps/074044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:45', 74, 45, 29, 576, 5540, 'وَكُنَّا نَخُوْضُ مَعَ الْخَاۤىِٕضِيْنَۙ', 'Bahkan, kami selalu berbincang (untuk tujuan yang batil) bersama para pembincang,', '', 'https://everyayah.com/data/Alafasy_128kbps/074045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:46', 74, 46, 29, 576, 5541, 'وَكُنَّا نُكَذِّبُ بِيَوْمِ الدِّيْنِۙ', 'dan kami selalu mendustakan hari Pembalasan,', '', 'https://everyayah.com/data/Alafasy_128kbps/074046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:47', 74, 47, 29, 576, 5542, 'حَتّٰىٓ اَتٰىنَا الْيَقِيْنُۗ', 'hingga datang kepada kami kematian.”', '', 'https://everyayah.com/data/Alafasy_128kbps/074047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:48', 74, 48, 29, 577, 5543, 'فَمَا تَنْفَعُهُمْ شَفَاعَةُ الشّٰفِعِيْنَۗ', 'Maka, tidak berguna lagi bagi mereka syafaat (pertolongan) dari para pemberi syafaat.', '', 'https://everyayah.com/data/Alafasy_128kbps/074048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:49', 74, 49, 29, 577, 5544, 'فَمَا لَهُمْ عَنِ التَّذْكِرَةِ مُعْرِضِيْنَۙ', 'Lalu, mengapa mereka (orang-orang kafir) berpaling dari peringatan (Allah)', '', 'https://everyayah.com/data/Alafasy_128kbps/074049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:50', 74, 50, 29, 577, 5545, 'كَاَنَّهُمْ حُمُرٌ مُّسْتَنْفِرَةٌۙ', 'seakan-akan mereka keledai liar yang terkejut', '', 'https://everyayah.com/data/Alafasy_128kbps/074050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:51', 74, 51, 29, 577, 5546, 'فَرَّتْ مِنْ قَسْوَرَةٍۗ', 'lari dari singa.', '', 'https://everyayah.com/data/Alafasy_128kbps/074051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:52', 74, 52, 29, 577, 5547, 'بَلْ يُرِيْدُ كُلُّ امْرِئٍ مِّنْهُمْ اَنْ يُّؤْتٰى صُحُفًا مُّنَشَّرَةًۙ', 'Bahkan, setiap orang dari mereka ingin diberi lembaran-lembaran (kitab) yang terbuka.', '', 'https://everyayah.com/data/Alafasy_128kbps/074052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:53', 74, 53, 29, 577, 5548, 'كَلَّاۗ بَلْ لَّا يَخَافُوْنَ الْاٰخِرَةَۗ', 'Sekali-kali tidak! Sebenarnya mereka tidak takut pada akhirat.', '', 'https://everyayah.com/data/Alafasy_128kbps/074053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:54', 74, 54, 29, 577, 5549, 'كَلَّآ اِنَّهٗ تَذْكِرَةٌ ۚ', 'Sekali-kali tidak! Sesungguhnya (Al-Qur’an) itu adalah suatu peringatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/074054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:55', 74, 55, 29, 577, 5550, 'فَمَنْ شَاۤءَ ذَكَرَهٗۗ', 'Siapa yang berkehendak tentu mengambil pelajaran darinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/074055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('74:56', 74, 56, 29, 577, 5551, 'وَمَا يَذْكُرُوْنَ اِلَّآ اَنْ يَّشَاۤءَ اللّٰهُ ۗهُوَ اَهْلُ التَّقْوٰى وَاَهْلُ الْمَغْفِرَةِ ࣖ', 'Mereka tidak akan mengambil pelajaran darinya (Al-Qur’an), kecuali (jika) Allah menghendakinya. Dialah yang (kita) patut bertakwa kepada-Nya dan yang berhak memberi ampunan.', '', 'https://everyayah.com/data/Alafasy_128kbps/074056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:1', 75, 1, 29, 577, 5552, 'لَآ اُقْسِمُ بِيَوْمِ الْقِيٰمَةِۙ', 'Aku bersumpah demi hari Kiamat.', '', 'https://everyayah.com/data/Alafasy_128kbps/075001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:2', 75, 2, 29, 577, 5553, 'وَلَآ اُقْسِمُ بِالنَّفْسِ اللَّوَّامَةِ ', 'Aku bersumpah demi jiwa yang sangat menyesali (dirinya sendiri).', '', 'https://everyayah.com/data/Alafasy_128kbps/075002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:3', 75, 3, 29, 577, 5554, 'اَيَحْسَبُ الْاِنْسَانُ اَلَّنْ نَّجْمَعَ عِظَامَهٗ ۗ', 'Apakah manusia mengira bahwa Kami tidak akan mengumpulkan (kembali) tulang-belulangnya?', '', 'https://everyayah.com/data/Alafasy_128kbps/075003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:4', 75, 4, 29, 577, 5555, 'بَلٰى قٰدِرِيْنَ عَلٰٓى اَنْ نُّسَوِّيَ بَنَانَهٗ ', 'Tentu, (bahkan) Kami mampu menyusun (kembali) jari-jemarinya dengan sempurna.', '', 'https://everyayah.com/data/Alafasy_128kbps/075004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:5', 75, 5, 29, 577, 5556, 'بَلْ يُرِيْدُ الْاِنْسَانُ لِيَفْجُرَ اَمَامَهٗۚ', 'Akan tetapi, manusia hendak berbuat maksiat terus-menerus.', '', 'https://everyayah.com/data/Alafasy_128kbps/075005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:6', 75, 6, 29, 577, 5557, 'يَسْـَٔلُ اَيَّانَ يَوْمُ الْقِيٰمَةِۗ', 'Dia bertanya, “Kapankah hari Kiamat itu?”', '', 'https://everyayah.com/data/Alafasy_128kbps/075006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:7', 75, 7, 29, 577, 5558, 'فَاِذَا بَرِقَ الْبَصَرُۙ', 'Apabila mata terbelalak (ketakutan),', '', 'https://everyayah.com/data/Alafasy_128kbps/075007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:8', 75, 8, 29, 577, 5559, 'وَخَسَفَ الْقَمَرُۙ', 'bulan pun telah hilang cahayanya,', '', 'https://everyayah.com/data/Alafasy_128kbps/075008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:9', 75, 9, 29, 577, 5560, 'وَجُمِعَ الشَّمْسُ وَالْقَمَرُۙ', 'serta matahari dan bulan dikumpulkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/075009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:10', 75, 10, 29, 577, 5561, 'يَقُوْلُ الْاِنْسَانُ يَوْمَىِٕذٍ اَيْنَ الْمَفَرُّۚ', 'pada hari itu manusia berkata, “Ke mana tempat lari?”', '', 'https://everyayah.com/data/Alafasy_128kbps/075010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:11', 75, 11, 29, 577, 5562, 'كَلَّا لَا وَزَرَۗ', 'Sekali-kali tidak! Tidak ada tempat berlindung.', '', 'https://everyayah.com/data/Alafasy_128kbps/075011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:12', 75, 12, 29, 577, 5563, 'اِلٰى رَبِّكَ يَوْمَىِٕذِ ِۨالْمُسْتَقَرُّۗ', '(Hanya) kepada Tuhanmu tempat kembali pada hari itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/075012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:13', 75, 13, 29, 577, 5564, 'يُنَبَّؤُا الْاِنْسَانُ يَوْمَىِٕذٍۢ بِمَا قَدَّمَ وَاَخَّرَۗ', 'Pada hari itu diberitakan kepada manusia apa yang telah dia kerjakan dan apa yang telah dia lalaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/075013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:14', 75, 14, 29, 577, 5565, 'بَلِ الْاِنْسَانُ عَلٰى نَفْسِهٖ بَصِيْرَةٌۙ', 'Bahkan, manusia menjadi saksi atas dirinya sendiri735)', '735) Anggota badan manusia menjadi saksi atas perbuatan yang telah mereka lakukan, seperti tersebut dalam surah an-Nūr (24): 24.', 'https://everyayah.com/data/Alafasy_128kbps/075014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:15', 75, 15, 29, 577, 5566, 'وَّلَوْ اَلْقٰى مَعَاذِيْرَهٗۗ', 'walaupun dia mengemukakan alasan-alasan(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/075015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:16', 75, 16, 29, 577, 5567, 'لَا تُحَرِّكْ بِهٖ لِسَانَكَ لِتَعْجَلَ بِهٖۗ', 'Jangan engkau (Nabi Muhammad) gerakkan lidahmu (untuk membaca Al-Qur’an) karena hendak tergesa-gesa (menguasai)-nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/075016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:17', 75, 17, 29, 577, 5568, 'اِنَّ عَلَيْنَا جَمْعَهٗ وَقُرْاٰنَهٗ ۚ', 'Sesungguhnya tugas Kamilah untuk mengumpulkan (dalam hatimu) dan membacakannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/075017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:18', 75, 18, 29, 577, 5569, 'فَاِذَا قَرَأْنٰهُ فَاتَّبِعْ قُرْاٰنَهٗ ۚ', 'Maka, apabila Kami telah selesai membacakannya, ikutilah bacaannya itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/075018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:19', 75, 19, 29, 577, 5570, 'ثُمَّ اِنَّ عَلَيْنَا بَيَانَهٗ ۗ', 'Kemudian, sesungguhnya tugas Kami (pula)-lah (untuk) menjelaskannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/075019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:20', 75, 20, 29, 578, 5571, 'كَلَّا بَلْ تُحِبُّوْنَ الْعَاجِلَةَۙ', 'Sekali-kali tidak! Bahkan, kamu mencintai kehidupan dunia, ', '', 'https://everyayah.com/data/Alafasy_128kbps/075020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:21', 75, 21, 29, 578, 5572, 'وَتَذَرُوْنَ الْاٰخِرَةَۗ', 'dan mengabaikan (kehidupan) akhirat. ', '', 'https://everyayah.com/data/Alafasy_128kbps/075021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:22', 75, 22, 29, 578, 5573, 'وُجُوْهٌ يَّوْمَىِٕذٍ نَّاضِرَةٌۙ', 'Wajah-wajah (orang mukmin) pada hari itu berseri-seri', '', 'https://everyayah.com/data/Alafasy_128kbps/075022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:23', 75, 23, 29, 578, 5574, 'اِلٰى رَبِّهَا نَاظِرَةٌ ۚ', '(karena) memandang Tuhannya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/075023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:24', 75, 24, 29, 578, 5575, 'وَوُجُوْهٌ يَّوْمَىِٕذٍۢ بَاسِرَةٌۙ', 'Wajah-wajah (orang kafir) pada hari itu muram', '', 'https://everyayah.com/data/Alafasy_128kbps/075024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:25', 75, 25, 29, 578, 5576, 'تَظُنُّ اَنْ يُّفْعَلَ بِهَا فَاقِرَةٌ ۗ', '(karena) mereka yakin akan ditimpakan kepadanya malapetaka yang sangat dahsyat.', '', 'https://everyayah.com/data/Alafasy_128kbps/075025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:26', 75, 26, 29, 578, 5577, 'كَلَّآ اِذَا بَلَغَتِ التَّرَاقِيَۙ', 'Sekali-kali tidak! Apabila (nyawa) telah sampai di kerongkongan,', '', 'https://everyayah.com/data/Alafasy_128kbps/075026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:27', 75, 27, 29, 578, 5578, 'وَقِيْلَ مَنْ ۜرَاقٍۙ', 'dan dikatakan (kepadanya), “Siapa yang (dapat) menyembuhkan?”', '', 'https://everyayah.com/data/Alafasy_128kbps/075027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:28', 75, 28, 29, 578, 5579, 'وَّظَنَّ اَنَّهُ الْفِرَاقُۙ', 'Dia pun yakin bahwa itulah waktu perpisahan (dengan dunia), ', '', 'https://everyayah.com/data/Alafasy_128kbps/075028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:29', 75, 29, 29, 578, 5580, 'وَالْتَفَّتِ السَّاقُ بِالسَّاقِۙ', 'dan bertautlah betis (kiri) dengan betis (kanan).736)', '736) Hal itu menggambarkan hebatnya penderitaan pada saat akan mati serta ketakutan akan meninggalkan dunia dan menghadapi akhirat.', 'https://everyayah.com/data/Alafasy_128kbps/075029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:30', 75, 30, 29, 578, 5581, 'اِلٰى رَبِّكَ يَوْمَىِٕذِ ِۨالْمَسَاقُ ۗ ࣖ', 'Kepada Tuhanmulah pada hari itu (manusia) digiring.', '', 'https://everyayah.com/data/Alafasy_128kbps/075030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:31', 75, 31, 29, 578, 5582, 'فَلَا صَدَّقَ وَلَا صَلّٰىۙ', 'Dia tidak membenarkan (Al-Qur’an dan Rasul) dan tidak melaksanakan salat. ', '', 'https://everyayah.com/data/Alafasy_128kbps/075031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:32', 75, 32, 29, 578, 5583, 'وَلٰكِنْ كَذَّبَ وَتَوَلّٰىۙ', 'Akan tetapi, dia mendustakan (Al-Qur’an) dan berpaling (dari kebenaran). ', '', 'https://everyayah.com/data/Alafasy_128kbps/075032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:33', 75, 33, 29, 578, 5584, 'ثُمَّ ذَهَبَ اِلٰٓى اَهْلِهٖ يَتَمَطّٰىۗ', 'Kemudian, dia pergi kepada keluarganya dengan menyombongkan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/075033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:34', 75, 34, 29, 578, 5585, 'اَوْلٰى لَكَ فَاَوْلٰىۙ', 'Celakalah kamu! Maka, celakalah! ', '', 'https://everyayah.com/data/Alafasy_128kbps/075034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:35', 75, 35, 29, 578, 5586, 'ثُمَّ اَوْلٰى لَكَ فَاَوْلٰىۗ', 'Kemudian, celakalah kamu! Maka, celakalah! ', '', 'https://everyayah.com/data/Alafasy_128kbps/075035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:36', 75, 36, 29, 578, 5587, 'اَيَحْسَبُ الْاِنْسَانُ اَنْ يُّتْرَكَ سُدًىۗ', 'Apakah manusia mengira akan dibiarkan begitu saja (tanpa pertanggungjawaban)?', '', 'https://everyayah.com/data/Alafasy_128kbps/075036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:37', 75, 37, 29, 578, 5588, 'اَلَمْ يَكُ نُطْفَةً مِّنْ مَّنِيٍّ يُّمْنٰى ', 'Bukankah dia dahulu setetes mani yang ditumpahkan (ke dalam rahim)? ', '', 'https://everyayah.com/data/Alafasy_128kbps/075037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:38', 75, 38, 29, 578, 5589, 'ثُمَّ كَانَ عَلَقَةً فَخَلَقَ فَسَوّٰىۙ', 'Kemudian, (mani itu) menjadi sesuatu yang melekat, lalu Dia menciptakan dan menyempurnakannya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/075038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:39', 75, 39, 29, 578, 5590, 'فَجَعَلَ مِنْهُ الزَّوْجَيْنِ الذَّكَرَ وَالْاُنْثٰىۗ', 'Lalu, Dia menjadikan darinya sepasang laki-laki dan perempuan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/075039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('75:40', 75, 40, 29, 578, 5591, 'اَلَيْسَ ذٰلِكَ بِقٰدِرٍ عَلٰٓى اَنْ يُّحْيِ َۧ الْمَوْتٰى ࣖ', 'Bukankah (Allah) itu kuasa (pula) menghidupkan orang mati?', '', 'https://everyayah.com/data/Alafasy_128kbps/075040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:1', 76, 1, 29, 578, 5592, 'هَلْ اَتٰى عَلَى الْاِنْسَانِ حِيْنٌ مِّنَ الدَّهْرِ لَمْ يَكُنْ شَيْـًٔا مَّذْكُوْرًا ', 'Bukankah telah datang kepada manusia suatu waktu dari masa yang ia belum merupakan sesuatu yang dapat disebut?', '', 'https://everyayah.com/data/Alafasy_128kbps/076001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:2', 76, 2, 29, 578, 5593, 'اِنَّا خَلَقْنَا الْاِنْسَانَ مِنْ نُّطْفَةٍ اَمْشَاجٍۖ نَّبْتَلِيْهِ فَجَعَلْنٰهُ سَمِيْعًاۢ بَصِيْرًا ', 'Sesungguhnya Kami telah menciptakan manusia dari setetes mani yang bercampur. Kami hendak mengujinya (dengan perintah dan larangan) sehingga menjadikannya dapat mendengar dan melihat.', '', 'https://everyayah.com/data/Alafasy_128kbps/076002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:3', 76, 3, 29, 578, 5594, 'اِنَّا هَدَيْنٰهُ السَّبِيْلَ اِمَّا شَاكِرًا وَّاِمَّا كَفُوْرًا ', 'Sesungguhnya Kami telah menunjukkan kepadanya jalan (yang lurus); ada yang bersyukur dan ada pula yang sangat kufur. ', '', 'https://everyayah.com/data/Alafasy_128kbps/076003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:4', 76, 4, 29, 578, 5595, 'اِنَّآ اَعْتَدْنَا لِلْكٰفِرِيْنَ سَلٰسِلَا۟ وَاَغْلٰلًا وَّسَعِيْرًا ', 'Sesungguhnya Kami telah menyediakan bagi orang-orang kafir rantai, belenggu, dan api (neraka) Sa‘ir (yang menyala-nyala). ', '', 'https://everyayah.com/data/Alafasy_128kbps/076004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:5', 76, 5, 29, 578, 5596, 'اِنَّ الْاَبْرَارَ يَشْرَبُوْنَ مِنْ كَأْسٍ كَانَ مِزَاجُهَا كَافُوْرًاۚ', 'Sesungguhnya orang-orang yang berbuat kebajikan akan minum (khamar) dari gelas yang campurannya air kafur,737)', '737) Kafur merupakan nama suatu mata air di surga yang warnanya putih, aromanya harum, dan enak rasanya. Kafur disediakan untuk hamba Allah yang taat.', 'https://everyayah.com/data/Alafasy_128kbps/076005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:6', 76, 6, 29, 579, 5597, 'عَيْنًا يَّشْرَبُ بِهَا عِبَادُ اللّٰهِ يُفَجِّرُوْنَهَا تَفْجِيْرًا ', '(yaitu) mata air (dalam surga) yang diminum oleh hamba-hamba Allah dan dapat mereka pancarkan dengan mudah.', '', 'https://everyayah.com/data/Alafasy_128kbps/076006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:7', 76, 7, 29, 579, 5598, 'يُوْفُوْنَ بِالنَّذْرِ وَيَخَافُوْنَ يَوْمًا كَانَ شَرُّهٗ مُسْتَطِيْرًا ', 'Mereka memenuhi nazar dan takut akan suatu hari yang azabnya merata di mana-mana. ', '', 'https://everyayah.com/data/Alafasy_128kbps/076007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:8', 76, 8, 29, 579, 5599, 'وَيُطْعِمُوْنَ الطَّعَامَ عَلٰى حُبِّهٖ مِسْكِيْنًا وَّيَتِيْمًا وَّاَسِيْرًا ', 'Mereka memberikan makanan yang disukainya kepada orang miskin, anak yatim, dan tawanan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/076008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:9', 76, 9, 29, 579, 5600, 'اِنَّمَا نُطْعِمُكُمْ لِوَجْهِ اللّٰهِ لَا نُرِيْدُ مِنْكُمْ جَزَاۤءً وَّلَا شُكُوْرًا ', '(Mereka berkata,) “Sesungguhnya kami memberi makanan kepadamu hanya demi rida Allah. Kami tidak mengharap balasan dan terima kasih darimu.', '', 'https://everyayah.com/data/Alafasy_128kbps/076009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:10', 76, 10, 29, 579, 5601, 'اِنَّا نَخَافُ مِنْ رَّبِّنَا يَوْمًا عَبُوْسًا قَمْطَرِيْرًا ', 'Sesungguhnya kami takut akan (azab) Tuhan kami pada suatu hari (ketika) orang-orang berwajah masam penuh kesulitan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/076010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:11', 76, 11, 29, 579, 5602, 'فَوَقٰىهُمُ اللّٰهُ شَرَّ ذٰلِكَ الْيَوْمِ وَلَقّٰىهُمْ نَضْرَةً وَّسُرُوْرًاۚ', 'Maka, Allah melindungi mereka dari keburukan hari itu dan memberikan keceriaan dan kegembiraan kepada mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/076011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:12', 76, 12, 29, 579, 5603, 'وَجَزٰىهُمْ بِمَا صَبَرُوْا جَنَّةً وَّحَرِيْرًاۙ', 'Dia memberikan balasan kepada mereka atas kesabarannya (berupa) surga dan (pakaian) sutra.', '', 'https://everyayah.com/data/Alafasy_128kbps/076012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:13', 76, 13, 29, 579, 5604, 'مُّتَّكِـِٕيْنَ فِيْهَا عَلَى الْاَرَاۤىِٕكِۚ  لَا يَرَوْنَ فِيْهَا شَمْسًا وَّلَا زَمْهَرِيْرًاۚ', 'Di dalamnya mereka duduk bersandar di atas dipan. Di sana mereka tidak merasakan terik matahari dan dingin yang menusuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/076013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:14', 76, 14, 29, 579, 5605, 'وَدَانِيَةً عَلَيْهِمْ ظِلٰلُهَا وَذُلِّلَتْ قُطُوْفُهَا تَذْلِيْلًا ', 'Naungan (pepohonan)-nya dekat di atas mereka dan sangat dimudahkan untuk memetik (buah)-nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/076014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:15', 76, 15, 29, 579, 5606, 'وَيُطَافُ عَلَيْهِمْ بِاٰنِيَةٍ مِّنْ فِضَّةٍ وَّاَكْوَابٍ كَانَتْ قَوَارِيْرَا۠ ', 'Diedarkan kepada mereka bejana-bejana dari perak dan gelas-gelas yang sangat bening (kacanya),', '', 'https://everyayah.com/data/Alafasy_128kbps/076015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:16', 76, 16, 29, 579, 5607, 'قَوَارِيْرَا۟ مِنْ فِضَّةٍ قَدَّرُوْهَا تَقْدِيْرًا ', 'kaca yang sangat bening terbuat dari perak. Mereka menentukan ukuran sesuai (dengan kehendak mereka). ', '', 'https://everyayah.com/data/Alafasy_128kbps/076016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:17', 76, 17, 29, 579, 5608, 'وَيُسْقَوْنَ فِيْهَا كَأْسًا كَانَ مِزَاجُهَا زَنْجَبِيْلًاۚ', 'Di sana mereka diberi segelas minuman bercampur jahe', '', 'https://everyayah.com/data/Alafasy_128kbps/076017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:18', 76, 18, 29, 579, 5609, 'عَيْنًا فِيْهَا تُسَمّٰى سَلْسَبِيْلًا ', '(yang didatangkan dari) sebuah mata air (di surga) yang dinamakan Salsabil.', '', 'https://everyayah.com/data/Alafasy_128kbps/076018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:19', 76, 19, 29, 579, 5610, '۞ وَيَطُوْفُ عَلَيْهِمْ وِلْدَانٌ مُّخَلَّدُوْنَۚ اِذَا رَاَيْتَهُمْ حَسِبْتَهُمْ لُؤْلُؤًا مَّنْثُوْرًا', 'Mereka dikelilingi oleh para pemuda yang tetap muda. Apabila melihatnya, kamu akan mengira bahwa mereka adalah mutiara yang bertaburan.', '', 'https://everyayah.com/data/Alafasy_128kbps/076019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:20', 76, 20, 29, 579, 5611, 'وَاِذَا رَاَيْتَ ثَمَّ رَاَيْتَ نَعِيْمًا وَّمُلْكًا كَبِيْرًا ', 'Apabila melihat (keadaan) di sana (surga), niscaya engkau akan melihat berbagai kenikmatan dan kerajaan yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/076020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:21', 76, 21, 29, 579, 5612, 'عٰلِيَهُمْ ثِيَابُ سُنْدُسٍ خُضْرٌ وَّاِسْتَبْرَقٌۖ وَّحُلُّوْٓا اَسَاوِرَ مِنْ فِضَّةٍۚ وَسَقٰىهُمْ رَبُّهُمْ شَرَابًا طَهُوْرًا ', 'Mereka berpakaian sutra halus yang hijau, sutra tebal, dan memakai gelang perak. Tuhan memberikan kepada mereka minuman yang suci.', '', 'https://everyayah.com/data/Alafasy_128kbps/076021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:22', 76, 22, 29, 579, 5613, 'اِنَّ هٰذَا كَانَ لَكُمْ جَزَاۤءً وَّكَانَ سَعْيُكُمْ مَّشْكُوْرًا ࣖ ', 'Sesungguhnya ini adalah balasan untukmu dan usahamu diterima dengan baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/076022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:23', 76, 23, 29, 579, 5614, 'اِنَّا نَحْنُ نَزَّلْنَا عَلَيْكَ الْقُرْاٰنَ تَنْزِيْلًاۚ', 'Sesungguhnya Kamilah yang benar-benar menurunkan Al-Qur’an kepadamu (Nabi Muhammad) secara berangsur-angsur.', '', 'https://everyayah.com/data/Alafasy_128kbps/076023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:24', 76, 24, 29, 579, 5615, 'فَاصْبِرْ لِحُكْمِ رَبِّكَ وَلَا تُطِعْ مِنْهُمْ اٰثِمًا اَوْ كَفُوْرًاۚ', 'Maka, bersabarlah untuk (melaksanakan) ketetapan Tuhanmu dan jangan ikuti pendosa dan orang yang sangat kufur di antara mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/076024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:25', 76, 25, 29, 579, 5616, 'وَاذْكُرِ اسْمَ رَبِّكَ بُكْرَةً وَّاَصِيْلًاۚ', 'Sebutlah nama Tuhanmu pada (waktu) pagi dan petang.', '', 'https://everyayah.com/data/Alafasy_128kbps/076025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:26', 76, 26, 29, 580, 5617, 'وَمِنَ الَّيْلِ فَاسْجُدْ لَهٗ وَسَبِّحْهُ لَيْلًا طَوِيْلًا ', 'Pada sebagian malam bersujudlah kepada-Nya dan bertasbihlah kepada-Nya pada malam yang panjang.', '', 'https://everyayah.com/data/Alafasy_128kbps/076026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:27', 76, 27, 29, 580, 5618, 'اِنَّ هٰٓؤُلَاۤءِ يُحِبُّوْنَ الْعَاجِلَةَ وَيَذَرُوْنَ وَرَاۤءَهُمْ يَوْمًا ثَقِيْلًا ', 'Sesungguhnya mereka (orang-orang kafir) itu mencintai kehidupan dunia dan meninggalkan di belakang mereka hari yang berat (akhirat). ', '', 'https://everyayah.com/data/Alafasy_128kbps/076027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:28', 76, 28, 29, 580, 5619, 'نَحْنُ خَلَقْنٰهُمْ وَشَدَدْنَآ اَسْرَهُمْۚ وَاِذَا شِئْنَا بَدَّلْنَآ اَمْثَالَهُمْ تَبْدِيْلًا ', 'Kami telah menciptakan mereka dan menguatkan persendian tubuh mereka. Jika berkehendak, Kami dapat mengganti (mereka) dengan orang-orang yang serupa mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/076028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:29', 76, 29, 29, 580, 5620, 'اِنَّ هٰذِهٖ تَذْكِرَةٌ ۚ فَمَنْ شَاۤءَ اتَّخَذَ اِلٰى رَبِّهٖ سَبِيْلًا ', 'Sesungguhnya ini adalah peringatan. Maka, siapa yang menghendaki (kebaikan bagi dirinya) tentu mengambil jalan menuju Tuhannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/076029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:30', 76, 30, 29, 580, 5621, 'وَمَا تَشَاۤءُوْنَ اِلَّآ اَنْ يَّشَاۤءَ اللّٰهُ ۗاِنَّ اللّٰهَ كَانَ عَلِيْمًا حَكِيْمًاۖ', 'Kamu tidak menghendaki (sesuatu) kecuali apabila dikehendaki Allah. Sesungguhnya Allah Maha Mengetahui lagi Maha Bijaksana. ', '', 'https://everyayah.com/data/Alafasy_128kbps/076030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('76:31', 76, 31, 29, 580, 5622, 'يُّدْخِلُ مَنْ يَّشَاۤءُ فِيْ رَحْمَتِهٖۗ وَالظّٰلِمِيْنَ اَعَدَّ لَهُمْ عَذَابًا اَلِيْمًا ࣖ', 'Dia memasukkan siapa pun yang Dia kehendaki ke dalam rahmat-Nya (surga). Bagi orang-orang zalim Dia sediakan azab yang pedih.', '', 'https://everyayah.com/data/Alafasy_128kbps/076031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:1', 77, 1, 29, 580, 5623, 'وَالْمُرْسَلٰتِ عُرْفًاۙ', 'Demi (malaikat-malaikat) yang diutus untuk membawa kebaikan', '', 'https://everyayah.com/data/Alafasy_128kbps/077001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:2', 77, 2, 29, 580, 5624, 'فَالْعٰصِفٰتِ عَصْفًاۙ', 'dan (malaikat-malaikat) yang terbang dengan kencang;', '', 'https://everyayah.com/data/Alafasy_128kbps/077002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:3', 77, 3, 29, 580, 5625, 'وَّالنّٰشِرٰتِ نَشْرًاۙ', 'demi (malaikat-malaikat) yang menyebarkan (rahmat Allah) dengan seluas-luasnya,738)', '738) Yang dimaksud adalah malaikat yang turun untuk membawa wahyu. Sebagian mufasir berpendapat bahwa yang dimaksud dengan an-nāsyirāt ialah angin yang bertiup disertai hujan.', 'https://everyayah.com/data/Alafasy_128kbps/077003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:4', 77, 4, 29, 580, 5626, 'فَالْفٰرِقٰتِ فَرْقًاۙ', 'dan (malaikat-malaikat) yang membedakan (antara yang baik dan yang buruk) dengan sejelas-jelasnya,', '', 'https://everyayah.com/data/Alafasy_128kbps/077004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:5', 77, 5, 29, 580, 5627, 'فَالْمُلْقِيٰتِ ذِكْرًاۙ', 'serta (malaikat-malaikat) yang menyampaikan wahyu', '', 'https://everyayah.com/data/Alafasy_128kbps/077005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:6', 77, 6, 29, 580, 5628, 'عُذْرًا اَوْ نُذْرًاۙ', 'untuk (menolak) alasan atau (memberi) peringatan,', '', 'https://everyayah.com/data/Alafasy_128kbps/077006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:7', 77, 7, 29, 580, 5629, 'اِنَّمَا تُوْعَدُوْنَ لَوَاقِعٌۗ', 'sesungguhnya apa yang dijanjikan kepadamu pasti terjadi.', '', 'https://everyayah.com/data/Alafasy_128kbps/077007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:8', 77, 8, 29, 580, 5630, 'فَاِذَا النُّجُوْمُ طُمِسَتْۙ', 'Apabila bintang-bintang dihapuskan (cahayanya),', '', 'https://everyayah.com/data/Alafasy_128kbps/077008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:9', 77, 9, 29, 580, 5631, 'وَاِذَا السَّمَاۤءُ فُرِجَتْۙ', 'apabila langit dibelah,', '', 'https://everyayah.com/data/Alafasy_128kbps/077009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:10', 77, 10, 29, 580, 5632, 'وَاِذَا الْجِبَالُ نُسِفَتْۙ', 'apabila gunung-gunung dihancurleburkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/077010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:11', 77, 11, 29, 580, 5633, 'وَاِذَا الرُّسُلُ اُقِّتَتْۗ', 'dan apabila rasul-rasul telah ditetapkan waktunya,739)', '739) Maksudnya adalah waktu untuk berkumpul bersama umat mereka masing-masing.', 'https://everyayah.com/data/Alafasy_128kbps/077011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:12', 77, 12, 29, 580, 5634, 'لِاَيِّ يَوْمٍ اُجِّلَتْۗ', '(niscaya dikatakan kepada mereka,) “Sampai hari apakah ditangguhkan (azab orang kafir itu)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/077012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:13', 77, 13, 29, 580, 5635, 'لِيَوْمِ الْفَصْلِۚ', 'Sampai hari Keputusan.', '', 'https://everyayah.com/data/Alafasy_128kbps/077013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:14', 77, 14, 29, 580, 5636, 'وَمَآ اَدْرٰىكَ مَا يَوْمُ الْفَصْلِۗ', 'Tahukah kamu apakah hari Keputusan itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/077014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:15', 77, 15, 29, 580, 5637, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:16', 77, 16, 29, 580, 5638, 'اَلَمْ نُهْلِكِ الْاَوَّلِيْنَۗ', 'Bukankah Kami telah membinasakan orang-orang dahulu?', '', 'https://everyayah.com/data/Alafasy_128kbps/077016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:17', 77, 17, 29, 580, 5639, 'ثُمَّ نُتْبِعُهُمُ الْاٰخِرِيْنَ ', 'Lalu, Kami susuli mereka dengan (mengazab) orang-orang yang datang kemudian.', '', 'https://everyayah.com/data/Alafasy_128kbps/077017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:18', 77, 18, 29, 580, 5640, 'كَذٰلِكَ نَفْعَلُ بِالْمُجْرِمِيْنَ ', 'Demikianlah Kami memperlakukan para pendurhaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/077018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:19', 77, 19, 29, 580, 5641, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:20', 77, 20, 29, 581, 5642, 'اَلَمْ نَخْلُقْكُّمْ مِّنْ مَّاۤءٍ مَّهِيْنٍۙ', 'Bukankah Kami menciptakanmu dari air yang hina (mani)?', '', 'https://everyayah.com/data/Alafasy_128kbps/077020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:21', 77, 21, 29, 581, 5643, 'فَجَعَلْنٰهُ فِيْ قَرَارٍ مَّكِيْنٍ', 'Kemudian, Kami meletakkannya di dalam tempat yang kukuh (rahim)', '', 'https://everyayah.com/data/Alafasy_128kbps/077021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:22', 77, 22, 29, 581, 5644, 'اِلٰى قَدَرٍ مَّعْلُوْمٍۙ', 'sampai waktu yang ditentukan.', '', 'https://everyayah.com/data/Alafasy_128kbps/077022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:23', 77, 23, 29, 581, 5645, 'فَقَدَرْنَاۖ فَنِعْمَ الْقٰدِرُوْنَ ', 'Lalu, Kami tentukan (bentuk dan waktu lahirnya). Maka, (Kamilah) sebaik-baik penentu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/077023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:24', 77, 24, 29, 581, 5646, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:25', 77, 25, 29, 581, 5647, 'اَلَمْ نَجْعَلِ الْاَرْضَ كِفَاتًاۙ', 'Bukankah Kami menjadikan bumi sebagai (tempat) berkumpul', '', 'https://everyayah.com/data/Alafasy_128kbps/077025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:26', 77, 26, 29, 581, 5648, 'اَحْيَاۤءً وَّاَمْوَاتًاۙ', 'bagi yang (masih) hidup dan yang (sudah) mati?740)', '740) Bumi mengumpulkan orang-orang hidup di permukaannya dan orang-orang mati dalam perutnya.', 'https://everyayah.com/data/Alafasy_128kbps/077026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:27', 77, 27, 29, 581, 5649, 'وَّجَعَلْنَا فِيْهَا رَوَاسِيَ شٰمِخٰتٍ وَّاَسْقَيْنٰكُمْ مَّاۤءً فُرَاتًاۗ', 'Kami menjadikan padanya gunung-gunung yang tinggi dan memberi minum kamu air yang tawar?', '', 'https://everyayah.com/data/Alafasy_128kbps/077027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:28', 77, 28, 29, 581, 5650, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:29', 77, 29, 29, 581, 5651, 'اِنْطَلِقُوْٓا اِلٰى مَا كُنْتُمْ بِهٖ تُكَذِّبُوْنَۚ', '(Dikatakan kepada orang-orang kafir,) “Pergilah menuju apa (neraka) yang selalu kamu dustakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/077029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:30', 77, 30, 29, 581, 5652, 'اِنْطَلِقُوْٓا اِلٰى ظِلٍّ ذِيْ ثَلٰثِ شُعَبٍ ', 'Pergilah menuju naungan (asap api neraka) yang mempunyai tiga cabang741)', '741) Maksudnya adalah tiga gejolak, yaitu di kanan, di kiri, dan di atas. Ini berarti bahwa azab itu mengepung orang-orang kafir dari segala penjuru.', 'https://everyayah.com/data/Alafasy_128kbps/077030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:31', 77, 31, 29, 581, 5653, 'لَا ظَلِيْلٍ وَّلَا يُغْنِيْ مِنَ اللَّهَبِۗ', 'yang tidak melindungi dan tidak menahan (panasnya) nyala api neraka.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/077031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:32', 77, 32, 29, 581, 5654, 'اِنَّهَا تَرْمِيْ بِشَرَرٍ كَالْقَصْرِۚ', 'Sesungguhnya ia (neraka) menyemburkan bunga api bagaikan istana (yang besar dan tinggi), ', '', 'https://everyayah.com/data/Alafasy_128kbps/077032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:33', 77, 33, 29, 581, 5655, 'كَاَنَّهٗ جِمٰلَتٌ صُفْرٌۗ', 'seakan-akan iringan unta (hitam) kekuning-kuningan.', '', 'https://everyayah.com/data/Alafasy_128kbps/077033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:34', 77, 34, 29, 581, 5656, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran). ', '', 'https://everyayah.com/data/Alafasy_128kbps/077034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:35', 77, 35, 29, 581, 5657, 'هٰذَا يَوْمُ لَا يَنْطِقُوْنَۙ', 'Inilah hari ketika mereka tidak dapat berbicara.', '', 'https://everyayah.com/data/Alafasy_128kbps/077035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:36', 77, 36, 29, 581, 5658, 'وَلَا يُؤْذَنُ لَهُمْ فَيَعْتَذِرُوْنَ ', 'Mereka tidak diizinkan (berbicara) sehingga (dapat) meminta maaf. ', '', 'https://everyayah.com/data/Alafasy_128kbps/077036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:37', 77, 37, 29, 581, 5659, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran). ', '', 'https://everyayah.com/data/Alafasy_128kbps/077037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:38', 77, 38, 29, 581, 5660, 'هٰذَا يَوْمُ الْفَصْلِ جَمَعْنٰكُمْ وَالْاَوَّلِيْنَ ', '(Dikatakan kepada mereka,) “Inilah hari Keputusan. Kami kumpulkan kamu dan orang-orang terdahulu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/077038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:39', 77, 39, 29, 581, 5661, 'فَاِنْ كَانَ لَكُمْ كَيْدٌ فَكِيْدُوْنِ ', 'Jika kamu punya tipu daya, lakukanlah terhadap-Ku.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/077039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:40', 77, 40, 29, 581, 5662, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ࣖ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:41', 77, 41, 29, 581, 5663, 'اِنَّ الْمُتَّقِيْنَ فِيْ ظِلٰلٍ وَّعُيُوْنٍۙ', 'Sesungguhnya orang-orang yang bertakwa berada dalam naungan (pepohonan surga yang teduh) dan (ada di sekitar) mata air ', '', 'https://everyayah.com/data/Alafasy_128kbps/077041.mp3');
